func numSubmatV1(mat [][]int) int {
	count := 0
	for h := 0; h < len(mat); h++ {
		for w := 0; w < len(mat[0]); w++ {
			for row := 0; row < len(mat)-h; row++ {
				for column := 0; column < len(mat[0])-w; column++ {
					if h == 0 && w == 0 {
						if mat[row][column] == 1 {
							count += 1
						}
					} else {
						filled := true
						for hor := 0; hor <= h; hor++ {
							for ver := 0; ver <= w; ver++ {
								if mat[row+hor][column+ver] == 0 {
									filled = false
									break
								}
							}
							if !filled {
								break
							}
						}
						if filled {
							count += 1
						}
					}
				}
			}
		}
	}

	return count
}

func numSubmatV2(mat [][]int) int {
	count := 0
	for row := 0; row < len(mat); row++ {
		for column := 0; column < len(mat[0]); column++ {
			if mat[row][column] == 0 {
				continue
			}

			for h := 0; h < len(mat)-row; h++ {
				for w := 0; w < len(mat[0])-column; w++ {
					filled := true
					for hor := 0; hor <= h; hor++ {
						for ver := 0; ver <= w; ver++ {
							if mat[row+hor][column+ver] == 0 {
								filled = false
								break
							}
						}
						if !filled {
							break
						}
					}
					if !filled {
						break
					}

					count += 1
				}
			}

		}
	}

	return count
}

